#!/usr/bin/env node
/**
 * stamp-note-kinds.cjs — Phase 2 migration of notes self-healing work.
 *
 * Walks content/Admin Notes/ and stamps `note-kind:` into every note's
 * frontmatter. The kind classifies the SHAPE of the note, separate from
 * `note-type` which classifies the DOMAIN (code/research/data/style).
 *
 * Five kinds:
 *   - reference: static knowledge (briefs, playbooks, specs, libraries,
 *     checklists, rules, framework docs). No status workflow.
 *   - report:    auto-generated by a producer script. Body shows
 *     findings; status mirrors body (Phase 1 wired this for any note
 *     that adds auto-resolve-when).
 *   - rollup:    auto-generated dashboards (Attention Queue, False
 *     Positive Log, sprint-schedule, pipeline-janitor-report). Read-only
 *     in the UI.
 *   - log:       dated snapshot (handoff, daily-briefing, session-log,
 *     daily reports tagged YYYY-MM-DD). Archived appearance, no actions.
 *   - ticket:    hand-managed work item (bug-queue, *-candidates,
 *     *-triage, *-followups, missing-profiles). Standard open/done flow.
 *
 * Existing notes that already have note-kind keep it. Re-run is idempotent.
 *
 * Usage:
 *   node scripts/stamp-note-kinds.cjs           # dry-run, prints classification
 *   node scripts/stamp-note-kinds.cjs --write   # apply to disk
 */

const fs = require('fs');
const path = require('path');
const { walkDir, parseFrontmatter } = require('./lib/shared.cjs');

const NOTES_DIR = path.join(__dirname, '..', 'content', 'Admin Notes');
const WRITE = process.argv.includes('--write');

// Filenames whose meaning isn't obvious from pattern matching alone.
// Explicit > implicit for these.
const EXPLICIT_KINDS = {
  'Attention Queue.md': 'rollup',
  'False Positive Log.md': 'rollup',
  'sprint-schedule.md': 'rollup',
  'pipeline-janitor-report.md': 'rollup',
  'External Services Setup.md': 'reference',
  'perplexity-prompt-library.md': 'reference',
  'bug-queue.md': 'ticket',
  'investigate-queue.md': 'ticket',
  'connection-suggestions.md': 'ticket',
  'missing-profiles.md': 'ticket',
  'missing-profile-candidates.md': 'ticket',
  'readiness-conflicts.md': 'ticket',
  'readiness-promotion-digest.md': 'rollup',
};

function inferKind(filename, body) {
  if (EXPLICIT_KINDS[filename]) return EXPLICIT_KINDS[filename];

  const base = filename.replace(/\.md$/, '');

  // Dated snapshots: handoff, daily, session, dated audits.
  if (/\d{4}-\d{2}-\d{2}/.test(base)) {
    if (
      /handoff|daily-briefing|session|signoff-reminder|rule-sort-pass|scripts-classification|lessons-learned|phase-\d/.test(
        base,
      )
    ) {
      return 'log';
    }
    // dated audits/reports keep report kind even when dated
    if (/audit|report|reconciliation/.test(base)) return 'report';
    return 'log';
  }

  // References: static knowledge documents.
  if (
    /(playbook|brief|spec|library|patterns|prompt|rules|guide|inventory|setup|plan|checklist|framework|legal|adr-\d)/.test(
      base,
    )
  ) {
    return 'reference';
  }

  // Reports: auto-generated by a producer.
  if (/-report$|-audit$|-survey$|-results$|-tier\d$/.test(base)) return 'report';

  // Tickets: queues, candidates, triage lists.
  if (/queue|candidates|triage|followups|backfill|unmatched|gap|priorities|drift/.test(base)) {
    return 'ticket';
  }

  // Body-based fallbacks: if frontmatter says generator/generated-by/source-script,
  // it's machine-produced → report. Otherwise default to ticket (the
  // most common "does this need work?" shape).
  // (caller passes data; we don't have it here — handled by main())
  return null;
}

function classify(filePath, content) {
  const filename = path.basename(filePath);
  const { data, body } = parseFrontmatter(content);
  if (data['note-kind']) {
    return { filename, current: data['note-kind'], inferred: data['note-kind'], change: false };
  }
  let inferred = inferKind(filename, body);
  if (!inferred) {
    if (data.generator || data['generated-by'] || data['source-script']) inferred = 'report';
    else inferred = 'ticket';
  }
  return { filename, current: null, inferred, change: true };
}

function setFrontmatterKey(content, key, value) {
  const fmMatch = content.match(/^(---\r?\n)([\s\S]*?)(\r?\n---)/);
  if (!fmMatch) return content;
  const [, openFence, fmBody, closeFence] = fmMatch;
  const keyLine = new RegExp(`^${key}:\\s*.*$`, 'm');
  let newFm;
  if (keyLine.test(fmBody)) {
    newFm = fmBody.replace(keyLine, `${key}: ${value}`);
  } else {
    newFm = fmBody + `\n${key}: ${value}`;
  }
  return openFence + newFm + closeFence + content.slice(fmMatch[0].length);
}

function main() {
  const files = walkDir(NOTES_DIR, '.md');
  const byKind = { reference: 0, report: 0, rollup: 0, log: 0, ticket: 0 };
  const flips = [];

  for (const f of files) {
    const content = fs.readFileSync(f, 'utf-8');
    const r = classify(f, content);
    byKind[r.inferred] = (byKind[r.inferred] || 0) + 1;
    if (r.change) {
      flips.push({ file: f, kind: r.inferred });
      if (WRITE) {
        // Some notes lack frontmatter entirely; only stamp if present.
        if (/^---/.test(content)) {
          fs.writeFileSync(f, setFrontmatterKey(content, 'note-kind', r.inferred), 'utf-8');
        }
      }
    }
  }

  console.log('═══════════════════════════════════════════════════');
  console.log('  Note-Kind Migration');
  console.log('═══════════════════════════════════════════════════');
  console.log(`  Mode: ${WRITE ? 'WRITE' : 'DRY RUN'}`);
  console.log(`  Notes scanned: ${files.length}`);
  console.log('');
  console.log('  Distribution after migration:');
  for (const [k, n] of Object.entries(byKind).sort((a, b) => b[1] - a[1])) {
    console.log(`    ${k.padEnd(10)} ${n}`);
  }
  console.log('');
  console.log(`  ${WRITE ? 'Stamped' : 'Would stamp'}: ${flips.length}`);
  if (!WRITE && flips.length) {
    console.log('');
    console.log('  Sample classifications:');
    for (const f of flips.slice(0, 15)) {
      console.log(`    ${path.basename(f.file).padEnd(45)} → ${f.kind}`);
    }
    if (flips.length > 15) console.log(`    ... and ${flips.length - 15} more`);
  }
  process.exit(0);
}

main();
